"use client";
import { useState } from "react";
import Header from "@/components/Header";

export default function AdminPage() {
    const [tab, setTab] = useState("audit");
    return (
        <>
            <Header />
            <div className="admin-container">
                <div className="admin-header">
                    <h1>Панель администратора</h1>
                    <p>Системный обзор — 21 апреля 2026</p>
                </div>
                <div className="stats-grid">
                    <div className="stat-card"><div className="stat-value" style={{color:'var(--cyan-400)'}}>3,842</div><div className="stat-label">Пользователей</div></div>
                    <div className="stat-card"><div className="stat-value">12,456</div><div className="stat-label">Книг в фонде</div></div>
                    <div className="stat-card"><div className="stat-value" style={{color:'var(--library-400)'}}>347</div><div className="stat-label">Активных выдач</div></div>
                    <div className="stat-card"><div className="stat-value" style={{color:'var(--red-400)'}}>₽45,200</div><div className="stat-label">Неоплаченных штрафов</div></div>
                </div>
                <div style={{display:'flex',gap:12,marginBottom:24,flexWrap:'wrap'}}>
                    <span className="status-badge st-ready"><span className="dot"></span>Основной сервер</span>
                    <span className="status-badge st-ready"><span className="dot"></span>База данных</span>
                    <span className="status-badge st-waiting"><span className="dot"></span>Резервный сервер</span>
                </div>
                <div className="tabs">
                    <button className={`tab ${tab==='audit'?'active':''}`} onClick={()=>setTab('audit')}>📋 Журнал аудит</button>
                    <button className={`tab ${tab==='users'?'active':''}`} onClick={()=>setTab('users')}>👥 Пользователи</button>
                    <button className={`tab ${tab==='settings'?'active':''}`} onClick={()=>setTab('settings')}>⚙️ Настройки</button>
                </div>
                {tab==='audit' && (
                    <div className="table-wrap">
                        <table>
                            <thead><tr><th>Действие</th><th>Пользователь</th><th>Время</th></tr></thead>
                            <tbody>
                            <tr><td>Изменение роли</td><td>Алексей Дмитриев</td><td>15 мин</td></tr>
                            <tr><td>Резервная копия БД</td><td>Система</td><td>1 час</td></tr>
                            <tr><td>Обновление системы v2.4.2</td><td>Система</td><td>3 часа</td></tr>
                            </tbody>
                        </table>
                    </div>
                )}
                {tab==='users' && <div className="table-wrap" style={{padding:32,textAlign:'center',color:'var(--ink-400)'}}>Управление пользователями (подключи Supabase)</div>}
                {tab==='settings' && <div className="table-wrap" style={{padding:32,textAlign:'center',color:'var(--ink-400)'}}>Системные настройки (подключи Supabase)</div>}
            </div>
        </>
    );
}