"use client";
import { useState, useEffect, useRef } from "react";
import { usePathname } from "next/navigation";

export default function Header({ onOpenAbout }) {
    const [notifOpen, setNotifOpen] = useState(false);
    const [profileOpen, setProfileOpen] = useState(false);
    const headerRef = useRef(null);
    const pathname = usePathname();

    useEffect(() => {
        const handleClickOutside = (e) => {
            if (headerRef.current && !headerRef.current.contains(e.target)) {
                setNotifOpen(false);
                setProfileOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const isActive = (path) => pathname === path;

    return (
        <header className="header" ref={headerRef}>
            <a href="/catalog" className="logo">
                <svg width="36" height="36" viewBox="0 0 40 40" fill="none" style={{flexShrink:0}}>
                    <rect x="4" y="8" width="14" height="24" rx="2" fill="#ec9428" opacity="0.9"/>
                    <rect x="10" y="6" width="14" height="24" rx="2" fill="#f6ca7d" opacity="0.9"/>
                    <rect x="16" y="10" width="14" height="24" rx="2" fill="#4f7e4f" opacity="0.9"/>
                </svg>
                Библиотека<span>Будущего</span>
            </a>

            <nav className="nav">
                <a href="/catalog" className={`nav-link ${isActive('/catalog') ? 'active' : ''}`}>Каталог</a>
                <a href="/dashboard" className={`nav-link ${isActive('/dashboard') ? 'active' : ''}`}>Личный кабинет</a>
                <button className={`nav-link ${isActive('/about') ? 'active' : ''}`} onClick={onOpenAbout}>О проекте</button>
            </nav>

            <div className="header-right">
                <div className="dropdown">
                    <button className="icon-btn" onClick={() => { setNotifOpen(!notifOpen); setProfileOpen(false); }}>
                        🔔 <span className="badge">3</span>
                    </button>
                    {notifOpen && (
                        <div className="dropdown-menu">
                            <div className="dropdown-header">🔔 Уведомления</div>
                            <button className="dropdown-item">Прочитать все</button>
                            <button className="dropdown-item" onClick={() => setNotifOpen(false)} style={{position:'absolute',top:8,right:8,padding:4}}>✕</button>
                        </div>
                    )}
                </div>

                <div className={`dropdown ${profileOpen ? 'open' : ''}`}>
                    <button className="user-btn" onClick={() => { setProfileOpen(!profileOpen); setNotifOpen(false); }}>
                        <div className="avatar">АК</div>
                        <span className="user-name">Анна К.▼</span>
                    </button>
                    <div className="dropdown-menu">
                        <div className="dropdown-header">
                            <div className="dropdown-header-name">Анна Ковалёва</div>
                            <div className="dropdown-header-email">anna.k@mail.ru</div>
                        </div>
                        <a href="/dashboard" className="dropdown-item">👤 Личный кабинет</a>
                        <button className="dropdown-item" onClick={() => { onOpenAbout(); setProfileOpen(false); }}>ℹ️ О проекте</button>
                        <div className="dropdown-divider"></div>
                        <a href="/logout" className="dropdown-item danger">🚪 Выйти</a>
                    </div>
                </div>
            </div>
        </header>
    );
}